// ============================================================
// VALIDATE INPUT — v3: suporta 5 tipos de análise
// ============================================================
const body = $json.body || {};
const editalId = body.edital_id;
const tipoAnalise = body.tipo_analise || 'resumo_executivo';

// Contexto adicional opcional (para análise com dados da empresa)
const contextoEmpresa = body.contexto_empresa || null;

if (!editalId) {
  throw new Error('Missing edital_id in request body');
}

const TIPOS_VALIDOS = [
  'resumo_executivo',
  'habilitacao',
  'verifica_edital',
  'contratos',
  'sg_contrato'
];

if (!TIPOS_VALIDOS.includes(tipoAnalise)) {
  throw new Error(`tipo_analise must be one of: ${TIPOS_VALIDOS.join(', ')}`);
}

return [{ json: {
  edital_id: editalId,
  tipo_analise: tipoAnalise,
  contexto_empresa: contextoEmpresa
} }];

// Check if edital was found — v3: includes pncp_detalhes, pncp_itens, arquivos_pncp
const rows = $input.all();
if (!rows.length || !rows[0].json.id) {
  throw new Error('Edital not found in database');
}

const edital = rows[0].json;
const tipoAnalise = $('Validate Input').first().json.tipo_analise;
const contextoEmpresa = $('Validate Input').first().json.contexto_empresa || null;
const hasTexto = edital.texto_completo && edital.texto_completo.length > 100;

return [{ json: {
  edital_id: edital.id,
  pncp_id: edital.pncp_id,
  titulo: edital.titulo,
  objeto: edital.objeto,
  orgao: edital.orgao,
  uf: edital.uf,
  modalidade: edital.modalidade,
  valor_estimado: edital.valor_estimado,
  data_encerramento: edital.data_encerramento,
  url_pncp: edital.url_pncp,
  raw_data: edital.raw_data,
  datajud_orgao: edital.datajud_orgao || null,
  pncp_detalhes: edital.pncp_detalhes || null,
  pncp_itens: edital.pncp_itens || null,
  arquivos_pncp: edital.arquivos_pncp || null,
  tipo_analise: tipoAnalise,
  contexto_empresa: contextoEmpresa,
  has_texto_completo: hasTexto,
  texto_completo: hasTexto ? edital.texto_completo : null,
  texto_total_caracteres: edital.texto_total_caracteres || 0
} }];

// After PDF extraction — handle failure gracefully
const extraction = $json;
const editalData = $('Check Edital Data').first().json;

// If extraction failed (neverError means we get error in response body)
if (!extraction.success) {
  // Continue with metadata-only analysis (fallback like v1)
  return [{ json: {
    ...editalData,
    texto_completo: null,
    texto_total_caracteres: 0,
    has_texto_completo: false
  } }];
}

return [{ json: {
  ...editalData,
  texto_completo: extraction.texto_completo,
  texto_total_caracteres: extraction.total_caracteres,
  has_texto_completo: true
} }];

// ============================================================
// BUILD ANALYSIS PROMPT — v3 MODULAR
// ============================================================
// Arquitetura: SYSTEM_BASE (fixo) + TASK_* (por tipo de análise)
// O system prompt NUNCA muda. Só o user message muda.
// ============================================================

const edital = $json;
const tipoAnalise = edital.tipo_analise;
const contextoEmpresa = edital.contexto_empresa;
const textoEdital = edital.texto_completo || '';

// Truncate if needed (~400k chars ≈ ~100k tokens)
const MAX_CHARS = 400000;
const textoTruncado = textoEdital.length > MAX_CHARS
  ? textoEdital.substring(0, MAX_CHARS) + '\n\n[... TEXTO TRUNCADO POR LIMITE DE TAMANHO ...]'
  : textoEdital;
const truncated = textoEdital.length > MAX_CHARS;
const hasFullText = textoTruncado && textoTruncado.length > 100;

// ============================================================
// SYSTEM PROMPT BASE — compartilhado por TODAS as tarefas
// ============================================================
const SYSTEM_BASE = `Você é um analista especializado em contratos e editais de licitação no Brasil, com domínio prático da Lei nº 14.133/2021 e normativos correlatos. Você lê documentos de licitação (editais, termos de referência, anexos, minutas de contrato, erratas, esclarecimentos) e produz análises técnicas estruturadas.

REGRAS INVIOLÁVEIS

1. LITERALIDADE: Relatar apenas o que estiver explicitamente previsto nos documentos fornecidos. Não presumir práticas usuais, interpretações extensivas nem entendimentos implícitos.
2. FONTES EXCLUSIVAS: Basear a análise apenas nos documentos fornecidos pelo usuário. Não usar fontes externas, pesquisas na internet nem conhecimento geral sobre editais.
3. LEITURA INTEGRAL: Ler todos os documentos fornecidos em sua totalidade — capas, índices, quadros, tabelas, notas de rodapé, apêndices, modelos e anexos.
4. AUSÊNCIAS: Se um requisito comumente esperado não for encontrado em nenhum documento, registrá-lo como "não exigido" — sem juízo de valor.
5. CONSOLIDAÇÃO: Se o mesmo requisito aparecer em mais de um ponto, consolidá-lo em um único item. Indicar todas as referências onde ocorre. Destacar diferenças de redação, condições adicionais, exceções ou prazos distintos entre as ocorrências.
6. IMPARCIALIDADE: Não emitir pareceres jurídicos, conclusões subjetivas, recomendações nem opiniões. Limitar-se a descrever e compilar informações.
7. SEM DIVAGAÇÕES: Não incluir saudações, comentários pessoais, menções a "boas práticas", sugestões nem conclusões subjetivas.

FORMATAÇÃO

- Idioma: Português (Brasil), linguagem formal, clara, objetiva.
- Estrutura: Relatório técnico com numeração hierárquica (1., 1.1, 1.1.1). Listas numeradas ou com marcadores. Até 3 níveis de profundidade.
- Títulos: Em MAIÚSCULAS com numeração. Sem sintaxe Markdown (#, ##) nem tags HTML.
- Rastreabilidade: Em cada item relevante, indicar a fonte em itálico: [seção/cláusula, pág. PDF X; pág. interna Y]. Se não houver paginação: [seção/título].
- Listas: Sem tabelas (exceto quando a tarefa solicitar explicitamente). Conteúdo em listas numeradas ou com marcadores.
- Layout: Sem recuos artificiais. Sem separadores visuais (---, _____, *, barras). Separação apenas por numeração e títulos.
- Datas: DD/MM/AAAA HH:MM (Brasília), em ordem cronológica. Converter prazos relativos em datas apenas se todos os elementos estiverem explícitos; caso contrário, manter o prazo relativo e indicar qual elemento falta.
- Valores: R$ 0.000,00 (ponto para milhares, vírgula para decimais).
- Organização: Respeitar as seções definidas pela tarefa. Não repetir conteúdo entre seções. Usar referências cruzadas quando necessário.

TRATAMENTO DE EDGE CASES

- Erratas que contradizem o corpo principal: Registrar ambas as redações, indicar a errata como prevalecente e anotar a contradição.
- Anexos referenciados mas não fornecidos: Registrar como "Anexo [X] referenciado em [localização] — não fornecido para análise".
- Documentos com OCR de baixa qualidade: Se trechos estiverem ilegíveis, indicar "[trecho ilegível em pág. PDF X]".
- Informações conflitantes entre documentos: Registrar ambas as versões com suas respectivas localizações, sem eleger uma como correta.`;

// ============================================================
// TASK PROMPTS — cada tipo de análise tem seu prompt específico
// ============================================================

const TASKS = {

  resumo_executivo: `TAREFA: RESUMO EXECUTIVO DO EDITAL

Realize a leitura integral do edital e de todos os anexos fornecidos. Elabore um relatório técnico estruturado nas 12 seções abaixo, nesta ordem exata, sem repetir informações entre seções.

1. INFORMAÇÕES ESSENCIAIS – dados do processo
- Órgão (ou entidade) licitante e unidade requisitante.
- Número da UASG, se aplicável.
- Número da licitação e número do processo administrativo.
- Modalidade da licitação, forma de disputa e plataforma ou local da sessão pública.
- Abrangência ou local(is) de execução/entrega do objeto.

2. RESUMO EXECUTIVO – visão geral
- Síntese do objeto (tipo de bem, serviço ou obra e escopo geral).
- Modalidade de licitação, forma de disputa e critério de julgamento das propostas.
- Principais prazos do certame e da execução contratual.
- Visão geral sobre valores (existência de orçamento estimado, forma de apresentação de preços).
- Principais riscos, exigências incomuns e pontos que merecem atenção.

3. DETALHAMENTO DO OBJETO – especificações e quantidades
- Natureza do objeto e resumo dos itens/lotes com quantidades.
- Principais requisitos técnicos: características, desempenho mínimo, qualidade, certificações.
- SLAs, métricas de desempenho e penalidades (se houver).
- Exigência de POCs, amostras, protótipos ou testes de conformidade.
- Critérios de aceite do objeto.
- Logística e implantação: entrega, transporte, instalação, treinamento.
- Garantia e suporte: prazos, manutenção, tempos de resposta/solução.
- Subcontratação: permissões, proibições, limites.
- Documentos do fabricante: cartas, declarações de parceria, autorizações.
- Cláusulas de PI, confidencialidade, LGPD, segurança da informação.
- Sustentabilidade e regras sobre marcas/modelos equivalentes.

4. PRAZOS E CRONOGRAMA – processo e execução
- Datas e horários do processo licitatório.
- Prazos de execução do contrato.
- Vigência contratual, prorrogações e marcos relevantes.

5. LOCAL, DATA E HORÁRIO DA LICITAÇÃO
- Local/plataforma da sessão pública.
- Data e horário oficiais de abertura.

6. DOCUMENTAÇÃO DE HABILITAÇÃO
- Habilitação jurídica.
- Regularidade fiscal e trabalhista.
- Qualificação técnica.
- Qualificação econômico-financeira.
- Declarações exigidas (todas, com localização exata).
- Exigências dispersas (fora da seção de habilitação).

7. REGRAS DE PARTICIPAÇÃO
- Requisitos gerais.
- Tratamento diferenciado (ME/EPP, cooperativas, PCD).
- Visita técnica.

8. CONSÓRCIOS
- Permitida, vedada ou omissa. Se permitida: requisitos.

9. CRITÉRIOS DE JULGAMENTO
- Critério adotado.
- Forma de classificação.
- Critérios de desempate.

10. VALORES
- Orçamento estimado (divulgado ou sigiloso).
- Valores de referência.
- Forma de cotação.
- Limites e inexequibilidade.

11. LEGISLAÇÃO APLICÁVEL
- Normas expressamente citadas (apenas identificação).

12. RISCOS, AMBIGUIDADES E OBSERVAÇÕES
- Exigências incomuns ou restritivas, com localização.
- Ambiguidades, contradições ou lacunas.
- Requisitos esperados mas não exigidos.
- Pontos que motivariam esclarecimento ou impugnação.`,

  habilitacao: `TAREFA: ANÁLISE DETALHADA DE HABILITAÇÃO

Examine o edital e todos os anexos fornecidos. Identifique e detalhe TODAS as exigências de habilitação presentes em qualquer parte dos documentos.

1. HABILITAÇÃO JURÍDICA
Documentos de constituição da empresa. Detalhar cada documento exigido com localização.

2. REGULARIDADE FISCAL E TRABALHISTA
Certidões negativas ou positivas com efeito de negativa. Para cada: nome exato, órgão emissor, localização no edital.

3. QUALIFICAÇÃO TÉCNICA
- Atestados: quantidade, parâmetros, regras de soma, concomitância.
- Certificações de qualidade.
- Registros profissionais.
- Equipe técnica ou equipamentos.
- POCs/amostras: prazos, critérios de aprovação/reprovação, consequências.

4. QUALIFICAÇÃO ECONÔMICO-FINANCEIRA
- Balanço e demonstrações: exercícios exigidos, exceções.
- Índices financeiros: fórmulas, valores mínimos, consequências.
- Certidões de falência/recuperação.
- Capital/patrimônio mínimo.
- Garantias de proposta: modalidades, valor, prazo.

5. DECLARAÇÕES EXIGIDAS
TODAS as declarações (incluindo texto corrido). Para cada: denominação, localização exata, existência de modelo.

6. EXIGÊNCIAS DISPERSAS
Requisitos de habilitação FORA da seção própria: TR, minuta, modelos, anexos técnicos, garantias/seguros, programa de integridade, consultas a cadastros de sanção.

7. RISCOS E OBSERVAÇÕES
- Exigências incomuns/restritivas.
- Ambiguidades/contradições sobre habilitação.
- Requisitos esperados mas não exigidos.
- Pontos para esclarecimento ou impugnação.`,

  verifica_edital: `TAREFA: VERIFICAÇÃO DE INTEGRIDADE DO EDITAL

Realize a leitura técnica de todos os documentos fornecidos. Compare o documento principal com os demais anexos.

1. DOCUMENTOS ANALISADOS
Para cada arquivo: nome, tipo identificado, número de páginas.

2. ANÁLISE DE COBERTURA
Para cada anexo: se está reproduzido integralmente no principal, se incorporado ou referenciado, divergências de redação/numeração.

3. DOCUMENTOS REFERENCIADOS MAS AUSENTES
Anexos mencionados mas não fornecidos nem presentes no consolidado. Referência exata.

4. DIVERGÊNCIAS IDENTIFICADAS
Diferenças materiais entre versões avulsas e consolidadas. Referências cruzadas inconsistentes.

5. CONCLUSÃO OBJETIVA
Se o principal consolida todos os demais. Lacunas de cobertura. Divergências que afetem a interpretação.`,

  contratos: `TAREFA: EXTRAÇÃO DE DADOS DE CONTRATOS E ADITIVOS

Leia os documentos fornecidos. Extraia exclusivamente informações explícitas.

REGRAS: Usar data da última assinatura eletrônica. Datas inferidas: registrar como "Data inferida a partir de [referência]". Data de início ausente = data de assinatura. Data de término ausente = início + duração. Informações ausentes = "Não informado". Entrada separada para cada aditivo.

Exceção à regra geral: USAR TABELA nesta tarefa.

Para cada documento extrair: tipo (Contrato/Aditivo/Anexo), número, data de assinatura, objeto/finalidade, data de início, data de término, duração (meses/dias), valor total, observações (renovações, prorrogações, reajustes, condições de vigência).

Após a tabela, listar inconsistências ou lacunas.`,

  sg_contrato: `TAREFA: SEGURO-GARANTIA — EXTRAÇÃO, CÁLCULO E EMAIL

ETAPA 1: EXTRAÇÃO E CÁLCULO
Para cada contrato/aditivo extrair: número do contrato, número do aditivo (se houver), valor, data de início, data de término, nome do cliente.
Calcular: valor do seguro = 5% do valor; validade = término + 3 meses.
Se algum dado estiver ausente, indicar claramente.

ETAPA 2: GERAÇÃO DO EMAIL
Para cada contrato/aditivo, gerar email:

Assunto: Solicitação de Emissão de Seguro Garantia - Contrato {número}

Corpo:
Senhores,

Trata-se de solicitação para emissão/endosso de seguro garantia no valor de R$ {valor calculado}, com validade de {data de início} até {data de término + 3 meses}, referente ao {aditivo, se houver} ao contrato {número}, firmado entre a IATR e a(o) {nome do cliente}.

Anexamos à presente o referido Contrato, Termos Aditivos e Apólices.

O tomador será a INTELIGÊNCIA ARTIFICIAL TECNOLOGIA E REFRIGERAÇÃO LTDA, sociedade empresária, com sede na Rua José Hipólito, nº 370, Cotiara, Barra Mansa, Rio de Janeiro, RJ, CEP 27.345-000, inscrita no CNPJ sob o nº 01.579.387/0001-45.`

};

// ============================================================
// MODEL SELECTION — modelo otimizado por tipo de tarefa
// ============================================================
const MODEL_MAP = {
  resumo_executivo: 'claude-sonnet-4-5',
  habilitacao: 'claude-sonnet-4-5',
  verifica_edital: 'claude-haiku-4-5',
  contratos: 'claude-haiku-4-5',
  sg_contrato: 'claude-haiku-4-5'
};

const MAX_TOKENS_MAP = {
  resumo_executivo: 16000,
  habilitacao: 12000,
  verifica_edital: 8000,
  contratos: 6000,
  sg_contrato: 4000
};

// ============================================================
// BUILD USER MESSAGE
// ============================================================
const taskPrompt = TASKS[tipoAnalise];
const selectedModel = MODEL_MAP[tipoAnalise] || 'claude-sonnet-4-5';
const maxTokens = MAX_TOKENS_MAP[tipoAnalise] || 16000;

let userMessage = taskPrompt + '\n\n---\n\n';

if (hasFullText) {
  userMessage += `DADOS DO EDITAL:\n` +
    `- Título: ${edital.titulo || 'N/I'}\n` +
    `- Órgão: ${edital.orgao || 'N/I'} (${edital.uf || 'N/I'})\n` +
    `- Modalidade: ${edital.modalidade || 'N/I'}\n` +
    `- PNCP ID: ${edital.pncp_id || 'N/I'}\n\n` +
    `TEXTO COMPLETO DO EDITAL E ANEXOS:\n\n` +
    textoTruncado;

  if (truncated) {
    userMessage += `\n\nNOTA: O texto foi truncado de ${textoEdital.length.toLocaleString()} para ${MAX_CHARS.toLocaleString()} caracteres por limite de contexto.`;
  }
} else {
  const valor = edital.valor_estimado;
  userMessage += `DADOS DISPONÍVEIS DO EDITAL (texto completo não disponível):\n\n` +
    `- Título: ${edital.titulo || 'N/I'}\n` +
    `- Órgão: ${edital.orgao || 'N/I'} (${edital.uf || 'N/I'})\n` +
    `- Modalidade: ${edital.modalidade || 'N/I'}\n` +
    `- Valor Estimado: ${typeof valor === 'number' ? 'R$ ' + valor.toLocaleString('pt-BR', {minimumFractionDigits: 2}) : valor || 'Não informado'}\n` +
    `- Encerramento: ${edital.data_encerramento || 'N/I'}\n` +
    `- URL: ${edital.url_pncp || ''}\n\n` +
    `Descrição do Objeto:\n${edital.objeto || 'N/I'}\n\n` +
    `NOTA: O texto completo do edital não está disponível. Elabore a análise com base nos dados acima, indicando claramente quais seções não puderam ser preenchidas por falta de informação.`;
}

// Contexto adicional da empresa (opcional, enviado pelo Portal)
if (contextoEmpresa) {
  userMessage += `\n\n---\n\nCONTEXTO DA EMPRESA LICITANTE:\n${contextoEmpresa}`;
}

// --- DataJud context injection (Feature 2 — from active v3) ---
let datajudContext = '';
const datajudOrgao = edital.datajud_orgao;
if (datajudOrgao && typeof datajudOrgao === 'object' && datajudOrgao.total_processos > 0) {
    const resumo = datajudOrgao.resumo || {};
    const porClasse = resumo.por_classe || {};
    const classeList = Object.entries(porClasse).map(([k, v]) => k + ' (' + v + ')').join(', ');
    datajudContext = '\n\n--- CONTEXTO JUDICIAL DO ÓRGÃO (DataJud/CNJ) ---\n';
    datajudContext += 'O órgão licitante possui ' + datajudOrgao.total_processos + ' processos judiciais registrados.\n';
    datajudContext += 'Distribuição por tipo: ' + classeList + '.\n';
    if (resumo.mais_recente) datajudContext += 'Processo mais recente: ' + resumo.mais_recente + '.\n';
    if (resumo.mais_antigo) datajudContext += 'Processo mais antigo: ' + resumo.mais_antigo + '.\n';
    datajudContext += 'Considere estas informações ao avaliar riscos na análise.\n';
}
userMessage += datajudContext;

return [{ json: {
  edital_id: edital.edital_id,
  pncp_id: edital.pncp_id,
  tipo_analise: tipoAnalise,
  system_prompt: SYSTEM_BASE,
  user_message: userMessage,
  selected_model: selectedModel,
  max_tokens: maxTokens,
  has_full_text: hasFullText,
  texto_chars: textoTruncado ? textoTruncado.length : 0
} }];

// ============================================================
// PROCESS LLM RESPONSE — v3.1: dynamic cost, modo_analise
// ============================================================
const llmResponse = $json;
// Build Partial Prompt or Build Analysis Prompt may have produced the data
let promptData;
try {
  promptData = $('Build Analysis Prompt').first().json;
} catch(e) {
  try {
    promptData = $('Build Partial Prompt').first().json;
  } catch(e2) {
    promptData = {};
  }
}

const choices = llmResponse.choices || [];
const content = choices.length > 0 ? (choices[0].message?.content || '') : '';
const model = llmResponse.model || promptData.selected_model || 'claude-sonnet-4-5';
const usage = llmResponse.usage || {};
const tokensIn = usage.prompt_tokens || 0;
const tokensOut = usage.completion_tokens || 0;
const tokensTotal = usage.total_tokens || (tokensIn + tokensOut);
const tipoAnalise = promptData.tipo_analise;
const modoAnalise = promptData.modo_analise || 'completo';

// Custo por modelo (USD per 1K tokens)
const COST_MAP = {
  'claude-sonnet-4-5':  { input: 0.003, output: 0.015 },
  'claude-haiku-4-5':   { input: 0.0008, output: 0.004 },
  'claude-opus-4-5':    { input: 0.015, output: 0.075 }
};
const modelBase = Object.keys(COST_MAP).find(k => model.includes(k)) || 'claude-sonnet-4-5';
const costs = COST_MAP[modelBase];
const custoUsd = (tokensIn * costs.input / 1000) + (tokensOut * costs.output / 1000);

if (!content) {
  return [{ json: {
    edital_id: promptData.edital_id,
    status: 'erro',
    resultado: JSON.stringify({
      error: true,
      message: llmResponse.error?.message || 'Empty response from LiteLLM',
      tipo_analise: tipoAnalise
    }),
    model: model,
    tokens: tokensTotal,
    tokens_input: tokensIn,
    tokens_output: tokensOut,
    custo_usd: custoUsd,
    tipo_analise: tipoAnalise,
    has_full_text: promptData.has_full_text || false,
    modo_analise: modoAnalise
  }}];
}

// Build JSONB fragment — Portal reads: resultado.resumo_executivo, resultado.habilitacao, etc.
const jsonbFragment = {};
jsonbFragment[tipoAnalise] = content;
jsonbFragment.tipo_analise = tipoAnalise;
jsonbFragment.versao_prompt = '3.1';
jsonbFragment.modelo_usado = model;
jsonbFragment.modo_analise = modoAnalise;

return [{ json: {
  edital_id: promptData.edital_id,
  pncp_id: promptData.pncp_id,
  status: 'concluida',
  resultado: JSON.stringify(jsonbFragment),
  model: model,
  tokens: tokensTotal,
  tokens_input: tokensIn,
  tokens_output: tokensOut,
  custo_usd: custoUsd,
  tipo_analise: tipoAnalise,
  has_full_text: promptData.has_full_text || false,
  modo_analise: modoAnalise
}}];

// ============================================================
// FORMAT RESPONSE — v3.3: dual-pattern Mode C detection
// N8N 2.7.5 behavior: accessing unexecuted node via $('Name').first()
// may throw OR return {json:{}}. We handle both:
// 1. try/catch: catches the throw case
// 2. sentinel field check: handles the {} return case
// ============================================================

let parsed = null;

// Try Process LLM Response (Modes A and B)
try {
  const llmData = $('Process LLM Response').first().json;
  if (llmData && llmData.edital_id) {
    parsed = llmData;
  }
} catch(e) {
  // Process LLM Response did not execute (Mode C path) — try fallback
}

// Fallback: Build Insufficient Response (Mode C)
if (!parsed) {
  try {
    const insufficientData = $('Build Insufficient Response').first().json;
    if (insufficientData && insufficientData.edital_id) {
      parsed = insufficientData;
    }
  } catch(e) {
    // Neither node executed — should not happen in normal flow
  }
}

// Last resort: empty shell to avoid null errors
if (!parsed) {
  parsed = {};
}

return [{ json: {
  success: parsed.status === 'concluida' || parsed.status === 'insuficiente',
  edital_id: parsed.edital_id,
  tipo_analise: parsed.tipo_analise,
  status: parsed.status,
  modelo: parsed.model,
  tokens_input: parsed.tokens_input || 0,
  tokens_output: parsed.tokens_output || 0,
  custo_usd: parsed.custo_usd || 0.0,
  com_texto_completo: parsed.has_full_text || false,
  modo_analise: parsed.modo_analise || 'unknown',
  versao_prompt: '3.3',
  timestamp: new Date().toISOString()
} }];

// ============================================================
// DETERMINE ANALYSIS MODE — v3.3
// A: texto_completo in DB > 500 chars → use cached text (Sonnet)
// A*: no text in DB but arquivos_pncp has PDFs → try extraction (→ A or B on fail)
// B: no text, no PDFs, has pncp_itens → partial analysis (Haiku)
// C: no text, no PDFs, no items → no LLM call
//
// Key fix: verifica_edital / contratos / sg_contrato are forced to insuficiente
// if no texto_completo (Mode B is not appropriate for those types)
// ============================================================
const edital = $json;

const textoCompleto = edital.texto_completo || '';
const temTexto = textoCompleto.length > 500;

let itens = edital.pncp_itens;
if (typeof itens === 'string') {
  try { itens = JSON.parse(itens); } catch(e) { itens = null; }
}
const itensList = Array.isArray(itens) ? itens : (itens && Array.isArray(itens.data) ? itens.data : null);
const temItens = itensList && itensList.length > 0;

let detalhes = edital.pncp_detalhes;
if (typeof detalhes === 'string') {
  try { detalhes = JSON.parse(detalhes); } catch(e) { detalhes = null; }
}

// Check if arquivos_pncp has downloadable files (PDFs or other docs)
let arquivos = edital.arquivos_pncp;
if (typeof arquivos === 'string') {
  try { arquivos = JSON.parse(arquivos); } catch(e) { arquivos = null; }
}
const arquivosList = Array.isArray(arquivos) ? arquivos :
                     (arquivos && Array.isArray(arquivos.data) ? arquivos.data : null);
const temArquivos = arquivosList && arquivosList.length > 0;

// Types that require full document — cannot work in Mode B (partial)
const REQUIRES_FULL_TEXT = ['verifica_edital', 'contratos', 'sg_contrato'];
const tipoRequiresFullText = REQUIRES_FULL_TEXT.includes(edital.tipo_analise);

let modo;
if (temTexto) {
  // Text already cached in DB — use it directly
  modo = 'completo';
} else if (tipoRequiresFullText) {
  // These types need full document: try extraction if files exist, else insuficiente
  modo = temArquivos ? 'completo' : 'insuficiente';
} else if (temArquivos) {
  // No text cached but files exist — try PDF extraction
  // Extract PDF Text node handles download; on failure Build Analysis Prompt uses metadata fallback
  modo = 'completo';
} else if (temItens) {
  modo = 'parcial';
} else {
  modo = 'insuficiente';
}

return [{ json: {
  ...edital,
  modo_analise: modo,
  tem_texto: temTexto,
  has_texto_completo: temTexto,
  tem_itens: temItens,
  tem_arquivos: temArquivos,
  pncp_itens_parsed: itensList,
  pncp_detalhes_parsed: detalhes
} }];

// ============================================================
// MODE C — Insufficient data, NO LLM call
// ============================================================
const edital = $json;

return [{ json: {
  edital_id: edital.edital_id,
  pncp_id: edital.pncp_id,
  status: 'insuficiente',
  resultado: JSON.stringify({
    [edital.tipo_analise]: 'Dados insuficientes para análise. Os documentos deste edital não estão disponíveis ou não puderam ser processados. Consulte diretamente no PNCP para baixar os documentos.',
    reason: 'insufficient_data',
    pncp_url: edital.url_pncp || '',
    versao_prompt: '3.1',
    modo_analise: 'insuficiente'
  }),
  model: 'none',
  tokens: 0,
  tokens_input: 0,
  tokens_output: 0,
  custo_usd: 0,
  tipo_analise: edital.tipo_analise,
  has_full_text: false,
  modo_analise: 'insuficiente'
} }];

// ============================================================
// BUILD PARTIAL ANALYSIS PROMPT — Mode B (items + metadata only)
// ============================================================
const edital = $json;
const tipoAnalise = edital.tipo_analise;
const itens = edital.pncp_itens_parsed || [];
const detalhes = edital.pncp_detalhes_parsed || {};

const SYSTEM_BASE = `Você é um analista especializado em contratos e editais de licitação no Brasil, com domínio prático da Lei nº 14.133/2021 e normativos correlatos. Você lê documentos de licitação (editais, termos de referência, anexos, minutas de contrato, erratas, esclarecimentos) e produz análises técnicas estruturadas.

REGRAS INVIOLÁVEIS

1. LITERALIDADE: Relatar apenas o que estiver explicitamente previsto nos documentos fornecidos. Não presumir práticas usuais, interpretações extensivas nem entendimentos implícitos.
2. FONTES EXCLUSIVAS: Basear a análise apenas nos documentos fornecidos pelo usuário. Não usar fontes externas, pesquisas na internet nem conhecimento geral sobre editais.
3. LEITURA INTEGRAL: Ler todos os documentos fornecidos em sua totalidade — capas, índices, quadros, tabelas, notas de rodapé, apêndices, modelos e anexos.
4. AUSÊNCIAS: Se um requisito comumente esperado não for encontrado em nenhum documento, registrá-lo como "não exigido" — sem juízo de valor.
5. CONSOLIDAÇÃO: Se o mesmo requisito aparecer em mais de um ponto, consolidá-lo em um único item. Indicar todas as referências onde ocorre. Destacar diferenças de redação, condições adicionais, exceções ou prazos distintos entre as ocorrências.
6. IMPARCIALIDADE: Não emitir pareceres jurídicos, conclusões subjetivas, recomendações nem opiniões. Limitar-se a descrever e compilar informações.
7. SEM DIVAGAÇÕES: Não incluir saudações, comentários pessoais, menções a "boas práticas", sugestões nem conclusões subjetivas.

FORMATAÇÃO

- Idioma: Português (Brasil), linguagem formal, clara, objetiva.
- Estrutura: Relatório técnico com numeração hierárquica (1., 1.1, 1.1.1). Listas numeradas ou com marcadores. Até 3 níveis de profundidade.
- Títulos: Em MAIÚSCULAS com numeração. Sem sintaxe Markdown (#, ##) nem tags HTML.
- Rastreabilidade: Em cada item relevante, indicar a fonte em itálico: [seção/cláusula, pág. PDF X; pág. interna Y]. Se não houver paginação: [seção/título].
- Listas: Sem tabelas (exceto quando a tarefa solicitar explicitamente). Conteúdo em listas numeradas ou com marcadores.
- Layout: Sem recuos artificiais. Sem separadores visuais (---, _____, *, barras). Separação apenas por numeração e títulos.
- Datas: DD/MM/AAAA HH:MM (Brasília), em ordem cronológica. Converter prazos relativos em datas apenas se todos os elementos estiverem explícitos; caso contrário, manter o prazo relativo e indicar qual elemento falta.
- Valores: R$ 0.000,00 (ponto para milhares, vírgula para decimais).
- Organização: Respeitar as seções definidas pela tarefa. Não repetir conteúdo entre seções. Usar referências cruzadas quando necessário.

TRATAMENTO DE EDGE CASES

- Erratas que contradizem o corpo principal: Registrar ambas as redações, indicar a errata como prevalecente e anotar a contradição.
- Anexos referenciados mas não fornecidos: Registrar como "Anexo [X] referenciado em [localização] — não fornecido para análise".
- Documentos com OCR de baixa qualidade: Se trechos estiverem ilegíveis, indicar "[trecho ilegível em pág. PDF X]".
- Informações conflitantes entre documentos: Registrar ambas as versões com suas respectivas localizações, sem eleger uma como correta.`;

// Format items list
let itensText = '';
if (itens.length > 0) {
  itensText = 'ITENS DA LICITAÇÃO:\n\n';
  for (const item of itens) {
    const sigiloso = item.orcamentoSigiloso;
    const valorUnit = sigiloso ? 'Sigiloso'
      : (item.valorUnitarioEstimado != null
          ? 'R$ ' + Number(item.valorUnitarioEstimado).toLocaleString('pt-BR', {minimumFractionDigits: 2})
          : 'N/I');
    itensText += `- Item ${item.numeroItem}: ${item.descricao || 'N/I'} | Qtd: ${item.quantidade || 'N/I'} ${item.unidadeMedida || ''} | Valor unit.: ${valorUnit} | Critério: ${item.criterioJulgamentoNome || 'N/I'}\n`;
  }
}

const amparoLegalRaw = detalhes.amparoLegal || detalhes.amparoLegalNome || '';
const amparoLegal = typeof amparoLegalRaw === 'object' ? (amparoLegalRaw.nome || '') : amparoLegalRaw;

const srp = detalhes.srp != null ? (detalhes.srp ? 'Sim' : 'Não') : 'N/I';

let valorEstimado = 'Não informado';
if (typeof edital.valor_estimado === 'number' && edital.valor_estimado > 0) {
  valorEstimado = 'R$ ' + edital.valor_estimado.toLocaleString('pt-BR', {minimumFractionDigits: 2});
} else if (detalhes.orcamentoSigilosoDescricao) {
  valorEstimado = detalhes.orcamentoSigilosoDescricao;
}

const userMessage = `TAREFA: ANÁLISE PARCIAL DO EDITAL (baseada em metadados da API PNCP)

AVISO: O texto completo do edital NÃO está disponível. Esta análise é baseada apenas nos dados estruturados da API PNCP (metadados e itens). Gere SOMENTE as 5 seções abaixo — não invente seções adicionais nem tente preencher seções que dependem do texto do edital.

1. INFORMAÇÕES ESSENCIAIS
2. RESUMO EXECUTIVO (parcial — apenas o que os dados estruturados permitem)
3. DETALHAMENTO DO OBJETO (itens da API com quantidades e valores)
10. VALORES (orçamento estimado conforme API — se sigiloso, declarar explicitamente)
12. RISCOS E LIMITAÇÕES DA ANÁLISE — liste as seções não geradas, o que falta para análise completa, e link para documentos no PNCP

Nota: Seções 4, 5, 6, 7, 8, 9, 11 dependem do texto do edital e não serão geradas nesta análise parcial.

---

DADOS DO EDITAL:
